Installation : `npm install -D vitest @vitest/ui jsdom @testing-library/react @testing-library/jest-dom`. Configuration dans `vite.config.ts` : ajouter `test: { globals: true, environment: 'jsdom' }`. Code du test :
```tsx
import { render, screen, fireEvent } from '@testing-library/react';
import { Button } from './Button';

test('affiche le texte et appelle onClick', () => {
  const handleClick = vi.fn();
  render(<Button onClick={handleClick}>Cliquez</Button>);
  const button = screen.getByText('Cliquez');
  expect(button).toBeInTheDocument();
  fireEvent.click(button);
  expect(handleClick).toHaveBeenCalledTimes(1);
});
```

```tsx
import { render, screen, fireEvent } from '@testing-library/react';
import { ProductCard } from './ProductCard';

const mockProduct = { id: 1, name: 'Smartphone', price: 299.99 };

test('affiche les infos produit et appelle onAddToCart avec le bon produit', () => {
  const mockAddToCart = vi.fn();
  render(<ProductCard product={mockProduct} onAddToCart={mockAddToCart} />);

  expect(screen.getByText('Smartphone')).toBeInTheDocument();
  expect(screen.getByText('299.99 FCFA')).toBeInTheDocument();

  const button = screen.getByRole('button', { name: /ajouter au panier/i });
  fireEvent.click(button);

  expect(mockAddToCart).toHaveBeenCalledTimes(1);
  expect(mockAddToCart).toHaveBeenCalledWith(mockProduct);
});
```

```tsx
import { renderHook, act } from '@testing-library/react';
import { useLocalStorage } from './useLocalStorage';

test('utilise localStorage correctement', () => {
  const { result } = renderHook(() => useLocalStorage('test-key', 'initial'));
  expect(result.current[0]).toBe('initial');

  act(() => { result.current[1]('updated'); });
  expect(result.current[0]).toBe('updated');
  expect(localStorage.getItem('test-key')).toBe(JSON.stringify('updated'));
});
```
